import{_ as e}from"./chunks/文件受限图.DsG20F9s.js";import{_ as i,o,c as r,a2 as n}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Moderacja obrazów i tryb dostępu","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/Safety/image-moderation-and-access-mode.md","filePath":"pl-PL/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),t={name:"pl-PL/Safety/image-moderation-and-access-mode.md"};function l(d,a,c,p,z,s){return o(),r("div",null,[...a[0]||(a[0]=[n('<h1 id="moderacja-obrazow-i-tryb-dostepu" tabindex="-1">Moderacja obrazów i tryb dostępu <a class="header-anchor" href="#moderacja-obrazow-i-tryb-dostepu" aria-label="Permalink to &quot;Moderacja obrazów i tryb dostępu&quot;">​</a></h1><p>Moderacja obrazów przypisuje przesłanym obrazom klasyfikację wiekową. Tryb dostępu określa, które klasyfikacje są widoczne publicznie.</p><p>Wpływa to na publiczną galerię, publiczne URL-e plików i Random Image API. Nie ogranicza panelu administracyjnego. Administratorzy nadal mogą widzieć i zarządzać wszystkimi plikami.</p><h2 id="gdzie-skonfigurowac" tabindex="-1">Gdzie skonfigurować <a class="header-anchor" href="#gdzie-skonfigurowac" aria-label="Permalink to &quot;Gdzie skonfigurować&quot;">​</a></h2><p>Otwórz panel administracyjny, a następnie przejdź do:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>Główne ustawienia to:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="co-robi-access-mode" tabindex="-1">Co robi Access Mode <a class="header-anchor" href="#co-robi-access-mode" aria-label="Permalink to &quot;Co robi Access Mode&quot;">​</a></h2><p>Access mode określa, które klasyfikacje wiekowe mogą być pokazywane publicznie.</p><p>Aktualne tryby:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>Publicznie widoczne ratingi</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>Tylko General</td></tr></tbody></table><p>Domyślny tryb to Adult mode.</p><p>Dla stron prywatnych lub z treściami dla dorosłych Adult mode może być właściwy. Dla bardziej zachowawczej galerii publicznej wybierz Youth, Teen albo Child mode.</p><h2 id="co-daje-właczenie-moderacji" tabindex="-1">Co daje włączenie moderacji <a class="header-anchor" href="#co-daje-właczenie-moderacji" aria-label="Permalink to &quot;Co daje włączenie moderacji&quot;">​</a></h2><p>Po włączeniu moderacji ImgBed wywołuje wybranego dostawcę podczas uploadu i zapisuje wykrytą klasyfikację wiekową.</p><p>Główne ratingi:</p><table tabindex="0"><thead><tr><th>Rating</th><th>Znaczenie</th></tr></thead><tbody><tr><td>General</td><td>Bezpieczna treść publiczna</td></tr><tr><td>R12</td><td>Lekko wrażliwa treść</td></tr><tr><td>R16</td><td>Umiarkowanie wrażliwa treść</td></tr><tr><td>R18</td><td>Treść dla dorosłych</td></tr></tbody></table><p>Wynik moderacji jest używany przy decyzji o publicznym dostępie.</p><p>Jeśli moderacja nie jest włączona albo stare pliki nie mają ratingu, są traktowane jako niesklasyfikowane. Pliki bez ratingu nie są automatycznie usuwane z publicznej galerii ani Random Image API tylko dlatego, że nie mają wyniku moderacji.</p><h2 id="wybor-dostawcy-moderacji" tabindex="-1">Wybór dostawcy moderacji <a class="header-anchor" href="#wybor-dostawcy-moderacji" aria-label="Permalink to &quot;Wybór dostawcy moderacji&quot;">​</a></h2><p>Dostępni dostawcy obejmują:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>Każdy dostawca ma inne wymagania:</p><ul><li>moderatecontent.com zwykle wymaga API Key.</li><li>nsfwjs zwykle wymaga URL-a endpointu API.</li><li>Sightengine wymaga API user i API secret.</li></ul><p>Wybierz według konta, dostępności i jakości wykrywania. Jeśli moderacja jest włączona i poprawnie skonfigurowana, ImgBed próbuje zapisać rating obrazu podczas uploadu.</p><h2 id="wpływ-na-publiczna-galerie" tabindex="-1">Wpływ na publiczną galerię <a class="header-anchor" href="#wpływ-na-publiczna-galerie" aria-label="Permalink to &quot;Wpływ na publiczną galerię&quot;">​</a></h2><p>Publiczna galeria filtruje pliki zgodnie z trybem dostępu.</p><p>Przykłady:</p><ul><li>Adult mode: obrazy R18 mogą się pojawić.</li><li>Youth mode: obrazy R18 są ukryte.</li><li>Teen mode: obrazy R16 i R18 są ukryte.</li><li>Child mode: pokazywane są tylko obrazy General.</li></ul><p>Dotyczy to tylko zwykłego publicznego dostępu. Panel administracyjny nadal pokazuje wszystkie pliki.</p><h2 id="wpływ-na-publiczne-url-e-plikow" tabindex="-1">Wpływ na publiczne URL-e plików <a class="header-anchor" href="#wpływ-na-publiczne-url-e-plikow" aria-label="Permalink to &quot;Wpływ na publiczne URL-e plików&quot;">​</a></h2><p>Publiczne URL-e plików to bezpośrednie linki obrazów otwierane przez odwiedzających.</p><p>Jeśli rating pliku jest dozwolony w bieżącym trybie, ImgBed zwraca oryginalny obraz.</p><p>Jeśli rating przekracza dozwolony poziom, zwykły publiczny dostęp nie zwraca oryginalnego obrazu. ImgBed zwraca skonfigurowany wynik blokady albo obraz zastępczy.</p><p>Przykład:</p><ul><li>Bieżący tryb to Child mode.</li><li>Obraz ma rating R18.</li><li>Odwiedzający otwiera publiczny URL bezpośrednio.</li><li>ImgBed nie zwraca temu odwiedzającemu oryginalnego obrazu R18.</li></ul><p><img src="'+e+'" alt="Obraz pliku z ograniczeniem" loading="lazy"></p><p>Administratorzy oglądający pliki w panelu administracyjnym nie są objęci tym ograniczeniem.</p><h2 id="wpływ-na-random-image-api" tabindex="-1">Wpływ na Random Image API <a class="header-anchor" href="#wpływ-na-random-image-api" aria-label="Permalink to &quot;Wpływ na Random Image API&quot;">​</a></h2><p>Random Image API również filtruje pulę kandydatów według trybu dostępu.</p><p>W Child mode losowe obrazy są wybierane tylko z plików General.</p><p>W Youth mode losowe obrazy mogą pochodzić z General, R12 i R16, ale nie z R18.</p><p>Dzięki temu Random Image API nie omija ograniczeń publicznej galerii.</p><h2 id="relacja-z-regułami-list" tabindex="-1">Relacja z regułami list <a class="header-anchor" href="#relacja-z-regułami-list" aria-label="Permalink to &quot;Relacja z regułami list&quot;">​</a></h2><p>Access mode nie jest jedyną regułą publicznego dostępu. Działa razem z allowlist i blocklist.</p><p>W skrócie:</p><ul><li>Treści z allowlist są publiczne w pierwszej kolejności.</li><li>Treści z blocklist nie mogą być oglądane bezpośrednio przez zwykłych odwiedzających.</li><li>Treści poza obiema listami są następnie sprawdzane według access mode.</li></ul><p>Jeśli obraz jest ograniczony zarówno przez rating wiekowy, jak i reguły list, zwykli odwiedzający nadal nie mogą zobaczyć oryginalnego pliku bezpośrednio.</p><h2 id="zalecane-ustawienia" tabindex="-1">Zalecane ustawienia <a class="header-anchor" href="#zalecane-ustawienia" aria-label="Permalink to &quot;Zalecane ustawienia&quot;">​</a></h2><p>Dla stron publicznych:</p><ul><li>Włącz moderację.</li><li>Wybierz tryb dostępu pasujący do odbiorców strony.</li><li>Użyj Child mode albo Teen mode dla odwiedzających w każdym wieku.</li><li>Unikaj Adult mode, jeśli nie chcesz pokazywać dojrzałych treści publicznie.</li><li>Sprawdzaj ratingi w panelu administracyjnym i poprawiaj ręcznie, gdy trzeba.</li></ul><p>Dla stron prywatnych lub osobistych:</p><ul><li>Adult mode zwykle jest wystarczający.</li><li>Włącz moderację, jeśli jest przydatna.</li><li>Sprawdzaj i poprawiaj ratingi w panelu administracyjnym według potrzeb.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="czy-pliki-znikna-z-panelu-administracyjnego-po-zmianie-access-mode" tabindex="-1">Czy pliki znikną z panelu administracyjnego po zmianie Access Mode? <a class="header-anchor" href="#czy-pliki-znikna-z-panelu-administracyjnego-po-zmianie-access-mode" aria-label="Permalink to &quot;Czy pliki znikną z panelu administracyjnego po zmianie Access Mode?&quot;">​</a></h3><p>Nie.</p><p>Access mode wpływa tylko na zwykły publiczny dostęp. Nie wpływa na panel administracyjny.</p><h3 id="dlaczego-publiczna-galeria-pokazuje-mniej-obrazow-po-przełaczeniu-na-child-mode" tabindex="-1">Dlaczego publiczna galeria pokazuje mniej obrazów po przełączeniu na Child mode? <a class="header-anchor" href="#dlaczego-publiczna-galeria-pokazuje-mniej-obrazow-po-przełaczeniu-na-child-mode" aria-label="Permalink to &quot;Dlaczego publiczna galeria pokazuje mniej obrazów po przełączeniu na Child mode?&quot;">​</a></h3><p>Child mode pozwala publicznie pokazywać tylko pliki General. R12, R16 i R18 są filtrowane.</p><h3 id="czy-publiczne-url-e-moga-nadal-otwierac-obrazy-dla-dorosłych" tabindex="-1">Czy publiczne URL-e mogą nadal otwierać obrazy dla dorosłych? <a class="header-anchor" href="#czy-publiczne-url-e-moga-nadal-otwierac-obrazy-dla-dorosłych" aria-label="Permalink to &quot;Czy publiczne URL-e mogą nadal otwierać obrazy dla dorosłych?&quot;">​</a></h3><p>Jeśli bieżący tryb dostępu nie pozwala na dany rating, zwykłe publiczne URL-e nie zwracają oryginalnego obrazu.</p><h3 id="czy-random-image-api-moze-zwrocic-ograniczone-obrazy" tabindex="-1">Czy Random Image API może zwrócić ograniczone obrazy? <a class="header-anchor" href="#czy-random-image-api-moze-zwrocic-ograniczone-obrazy" aria-label="Permalink to &quot;Czy Random Image API może zwrócić ograniczone obrazy?&quot;">​</a></h3><p>Nie.</p><p>Random Image API filtruje kandydatów według bieżącego trybu dostępu.</p><h3 id="co-ze-starymi-obrazami-bez-ratingu" tabindex="-1">Co ze starymi obrazami bez ratingu? <a class="header-anchor" href="#co-ze-starymi-obrazami-bez-ratingu" aria-label="Permalink to &quot;Co ze starymi obrazami bez ratingu?&quot;">​</a></h3><p>Obrazy bez ratingu nie są automatycznie ukrywane tylko dlatego, że nie mają wyniku moderacji. Możesz później zmienić ich rating w panelu administracyjnym.</p>',67)])])}const b=i(t,[["render",l]]);export{u as __pageData,b as default};
